#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10,INF=0x7fffffff;
struct Pair
{
	int x,y;inline Pair(const int &xx=0,const int &yy=0){x=xx;y=yy;}
	inline bool operator<(const Pair&Q)const{return x==Q.x?y<Q.y:x<Q.x;}
	inline bool operator==(const Pair&Q)const{return x==Q.x&&y==Q.y;}
	inline bool operator<=(const Pair&Q)const{return x==Q.x?y<=Q.y:x<Q.x;}
};
template<typename T> inline int max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline int min(const T&x,const T&y){return x<y?x:y;}
namespace QwQ
{
	int s,t,que[N*20],H,T,head[N],des[N<<1],nxt[N<<1],cap[N<<1],cgt=1,cst[N<<1],h2[N],mnc,f2[N],DN,dis[N];bool inq[N],vis[N];
	inline void ins(const int &x,const int &y,const int &c,const int &w)
	{
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;cst[cgt]=w;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;cst[cgt]=-w;
	}
	inline bool spfa()
	{
		memset(dis,0x7f,(t+5)<<2);dis[que[H=T=1]=s]=0;while(H<=T)
		{
			int u=que[H++];inq[u]=false;grep(u,i)
			{
				int v=des[i];if(cap[i]&&dis[u]+cst[i]<dis[v])
				{
					dis[v]=dis[u]+cst[i];
					if(!inq[v])inq[que[++T]=v]=true;
				}
			}
		}
		return dis[t]!=dis[0];
	}
	inline int dfs(const int &u=s,int in=INF)
	{
		if(u==t)return in;int out=0;vis[u]=true;for(int &i=h2[u];i;i=nxt[i])
		{
			int v=des[i];if(!vis[v]&&cap[i]&&dis[v]==dis[u]+cst[i])
			{
				int tmp=dfs(v,min(in,cap[i]));out+=tmp;in-=tmp;
				cap[i]-=tmp;cap[i^1]+=tmp;mnc+=tmp*cst[i];if(!in)break;
			}
		}
		if(!out)dis[u]=dis[0];return vis[u]=false,out;
	}
	inline Pair dinic(const int &u,const int &v){s=u;t=v;int res=0;while(spfa())memcpy(h2,head,(t+5)<<2),res+=dfs();return Pair(res,mnc);}
}
using namespace QwQ;
int n,m,a[110][110];
int main()
{
	m=read();n=read();s=n*m+n+1;t=s+1;
	rep(1,n,i)rep(1,m,j)a[i][j]=read();
	rep(1,n*m,i)ins(s,i,1,0);rep(n*m+1,n*m+n,i)ins(i,t,1,0);
	rep(1,m,i)rep(1,n,j)rep(1,n,k)ins((i-1)*n+k,j+n*m,1,a[j][i]*k);
	Pair res=dinic(s,t);printf("%.2lf\n",1.*res.y/n);
}
